// XCVsimd Clang builtins: element-wise ops lower to native packed-vector IR
// (selecting the cv.*.h / cv.*.b instructions); the non-representable ops
// (dot products, shuffle, pack, complex, extract/insert) lower to the
// dedicated llvm.riscv.cv.simd.* intrinsics.

#include <stdint.h>

